def find_indices_with(term):
    nterm = normalize_ar(term)
    res = []
    for i, h in enumerate(hadith):
        txt = (h.get('Matn') or '') + ' ' + (h.get('hadithTxt') or '')
        ntxt = normalize_ar(txt)
        if nterm in ntxt:
            res.append((i, ntxt[max(0, ntxt.index(nterm)-50): ntxt.index(nterm)+len(nterm)+50]))
    return res

